      const recordingBackground =
        [sourceCanvas, sourceCanvas.parentElement, document.body]
          .map(element => element && window.getComputedStyle(element).backgroundColor)
          .find(color => color && color !== "transparent" && color !== "rgba(0, 0, 0, 0)") || "#ffffff";
      let recordingFrame = 0;
